    let score = 0, depth = 0;
    for (let i = 0; i < s.length; i++) {
        if (s[i] === '(')
            depth++;
        else {
            depth--;
            if (s[i - 1] === '(')
                score += 1 << depth;
        }
    }
    return score;
}
